#include <stdio.h>
#include <string.h>
#define MAX 10000
#define MAX_LINE 80
int main() {
    int N;
    scanf("%d", &N);
    getchar(); // consume newline
    char lines[N][MAX_LINE];
    for (int i = 0; i < N; i++) {
        fgets(lines[i], MAX_LINE, stdin);
        lines[i][strcspn(lines[i], "\n")] = 0; // remove newline
    }
    for (int i = N - 1; i >= 0; i--) {
        char *word = strtok(lines[i], " ");
        while (word != NULL) {
            printf("%s ", word);
            word = strtok(NULL, " ");
        }
        printf("\n");
    }
    return 0;
}

code.C++:
#include <iostream>
#include <vector>
#include <sstream>
using namespace std;
int main() {
    int N;
    cin >> N;
    cin.ignore(); // ignore newline
    vector<string> lines(N);
    for (int i = 0; i < N; i++) {
        getline(cin, lines[i]);
    }
    for (int i = N - 1; i >= 0; i--) {
        istringstream iss(lines[i]);
        vector<string> words;
        string word;
        while (iss >> word) {
            words.push_back(word);
        }
        for (int j = words.size() - 1; j >= 0; j--) {
            cout << words[j] << " ";
        }
        cout << endl;
    }
    return 0;
}

