const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
let N = parseInt(lines[idx++]);
let inputLines = lines.slice(idx, idx + N);
idx += N;
let output = '';
for (let i = N - 1; i >= 0; i--) {
    let words = inputLines[i].split(' ');
    let reversedWords = words.reverse().join(' ');
    output += reversedWords + '\n';
}
